import{_ as s,o as t,c as r,a2 as i}from"./chunks/framework.Cuq8tsM6.js";const c=JSON.parse('{"title":"Paiement des Revenus","description":"","frontmatter":{"title":"Paiement des Revenus"},"headers":[],"relativePath":"docs/fr/publishers/payouts.md","filePath":"docs/fr/publishers/payouts.md"}'),a={name:"docs/fr/publishers/payouts.md"};function o(n,e,d,l,p,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="gestion-des-revenus-et-paiements" tabindex="-1">Gestion des Revenus et Paiements <a class="header-anchor" href="#gestion-des-revenus-et-paiements" aria-label="Permalink to &quot;Gestion des Revenus et Paiements&quot;">​</a></h1><p>Suivez vos gains en temps réel et optimisez votre trésorerie pour éviter les frais.</p><hr class="my-6"><h2 class="text-purple-200 mb-4">Suivi du P&amp;L (Wallet)</h2><div style="background-color:var(--vp-c-bg-soft);border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;margin-bottom:40px;"><p class="fs-4 mb-2">Vos revenus sont visibles en temps réel sur la plateforme.</p><p class="mb-0">Consultez à tout moment votre <strong>Solde Disponible</strong> = <em>(Revenus validés) - (Retraits effectués)</em>.</p></div><h2 class="text-grey-dk-000 mb-4">Politique de Retrait et Frais</h2><p>Nous encourageons le regroupement des paiements pour limiter les frictions administratives.</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(300px, 1fr));gap:20px;margin-bottom:40px;"><div style="border:2px solid #28a745;background-color:#f0fcf4;border-radius:8px;padding:24px;"><h3 class="mt-0 text-green-200">1️⃣ Le Premier Retrait</h3><div class="fs-8 fw-700 text-green-200 mb-2">GRATUIT</div><p class="mb-0">Votre tout premier virement est <strong>100% gratuit</strong>, quel que soit le montant. Aucun frais de gestion.</p></div><div style="border:1px solid var(--vp-c-divider);background-color:var(--vp-c-bg-elv);border-radius:8px;padding:24px;"><h3 class="mt-0 text-grey-dk-000">🔄 Les Retraits Suivants</h3><div class="fs-8 fw-700 text-grey-dk-000 mb-2">5% <span class="fs-4 fw-300">de frais</span></div><p class="mb-0">Des frais de gestion s&#39;appliquent sur le montant demandé.</p><p class="fs-2 text-grey-dk-000 mt-2"><em>Ex: Pour 1 000€ retirés, vous recevez 950€.</em></p></div></div><h2 class="text-purple-200 mb-4">Comment éviter les frais de 5% ?</h2><div style="display:flex;gap:20px;flex-wrap:wrap;"><div style="flex:1;min-width:300px;border:1px solid #2563eb;border-radius:8px;padding:24px;"><h3 class="mt-0 text-purple-200">Option A : Le &quot;Cumul&quot;</h3><p>Laissez vos revenus s&#39;accumuler sur votre cagnotte.</p><ul><li><strong>Avantage :</strong> En espaçant vos retraits, retirez vos revenus une fois par an, en un retrait groupé <strong>sans frais</strong>.</li></ul></div><div style="flex:1;min-width:300px;border:1px solid #2d6fd6;border-radius:8px;padding:24px;"><h3 class="mt-0 text-blue-200">Option B : Le Réinvestissement</h3><p>Utilisez votre solde pour financer vos propres campagnes d&#39;acquisition (Asile Colis ou Emailing).</p><ul><li><strong>Avantage :</strong> 1€ gagné = 1€ réinvesti en trafic. Aucune friction bancaire, transfert immédiat.</li></ul></div></div><div class="mt-6 p-4 bg-grey-lt-000 border rounded-1"><h4 class="mt-0">💡 Pourquoi cette politique ?</h4><ol class="mb-0 pl-4"><li class="mb-2"><strong>Réduction de l&#39;Admin :</strong> Limiter le volume de petits virements nous permet de maintenir des coûts de plateforme bas.</li><li><strong>Sécurité (Buffer) :</strong> Ce délai de trésorerie sécurise les fonds en cas d&#39;impayés annonceurs, vous garantissant d&#39;être payé même si l&#39;annonceur a du retard.</li></ol></div>',11)])])}const v=s(a,[["render",o]]);export{c as __pageData,v as default};
